5	describe("MHPCO Claim Office", () => {
6	  // === Quote: empty and basic single items ===
7	  it("should return premium of 5 G (processing fee only) for an empty item list", () => {
8	    const result = runScenario({
9	      command: "quote",
10	      customer: { yearsInsured: 0, contractNumber: 1 },
11	      items: [],
12	    });
13	    expect(result).toEqual({ premium: 5 });
