16	    const result = runScenario({
17	      command: "quote",
18	      customer: { yearsInsured: 0, contractNumber: 1 },
19	      items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	    });
21	    expect(result).toEqual({ premium: 115 });
22	  });
23	  it("should quote a single amulet at 71 G (60 base + 6 first-insurance + 5 fee)", () => {
24	    const result = runScenario({
25	      command: "quote",
26	      customer: { yearsInsured: 0, contractNumber: 1 },
27	      items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
28	    });
29	    expect(result).toEqual({ premium: 71 });
30	  });
31	  it("should quote a single staff at 93 G (80 base + 8 first-insurance + 5 fee)", () => {
32	    const result = runScenario({
33	      command: "quote",
34	      customer: { yearsInsured: 0, contractNumber: 1 },
35	      items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
36	    });
37	    expect(result).toEqual({ premium: 93 });
38	  });
39	  it("should quote a single potion at 49 G (40 base + 4 first-insurance + 5 fee)", () => {
40	    const result = runScenario({
41	      command: "quote",
42	      customer: { yearsInsured: 0, contractNumber: 1 },
43	      items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
44	    });
45	    expect(result).toEqual({ premium: 49 });
46	  });
47	  it("should quote a single rune at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)", () => {
48	    const result = runScenario({
49	      command: "quote",
50	      customer: { yearsInsured: 0, contractNumber: 1 },
51	      items: [{ type: "rune", material: "stone", enchantment: 0, cursed: false }],
52	    });
53	    expect(result).toEqual({ premium: 33 });
54	  });
55	  it("should quote a single moonstone at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)", () => {
56	    const result = runScenario({
57	      command: "quote",
58	      customer: { yearsInsured: 0, contractNumber: 1 },
59	      items: [{ type: "moonstone", material: "crystal", enchantment: 0, cursed: false }],
60	    });
61	    expect(result).toEqual({ premium: 33 });
62	  });
63	
64	  // === Quote: multiple distinct items ===
65	  it("should quote multiple distinct items by summing their item premiums plus the 5 G fee", () => {
66	    const result = runScenario({
67	      command: "quote",
68	      customer: { yearsInsured: 0, contractNumber: 1 },
69	      items: [
70	        { type: "sword", material: "steel", enchantment: 0, cursed: false },
71	        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
72	      ],
73	    });
74	    expect(result).toEqual({ premium: 181 });
75	  });
76	
77	  // === Quote: components and blocks of 3 alike ===
78	  it.todo("should quote exactly 3 alike runes as a block with 60 G base premium (plus first-insurance and fee)");
79	  it.todo("should quote exactly 3 alike moonstones as a block with 60 G base premium (plus first-insurance and fee)");
80	  it.todo("should NOT treat 4 alike runes as a block (charge each rune individually)");
81	  it.todo("should NOT treat 2 alike runes as a block (charge each rune individually)");
82	
83	  // === Quote: item-specific modifiers ===
84	  it.todo("should add 50% cursed surcharge on a cursed item's base premium");
85	  it.todo("should add 30% high-enchantment surcharge for an item with enchantment >= 5");
86	  it.todo("should NOT add high-enchantment surcharge for enchantment level < 5");
87	  it.todo("should stack cursed and high-enchantment surcharges additively on the item's base premium");
88	
89	  // === Quote: policy-wide modifiers ===
90	  it.todo("should apply -20% loyalty discount when customer has been insured for >= 2 years");
91	  it.todo("should NOT apply loyalty discount when customer has been insured < 2 years");
92	  it.todo("should apply -15% follow-up discount for the customer's second contract");
93	  it.todo("should NOT apply follow-up discount for the customer's first contract");
94	
95	  // === Quote: multiple items of same type (separate insurance) ===
96	  it.todo("should treat two swords as separate insurance entries (each charged individually)");
97	
98	  // === Quote: rounding ===
99	  it.todo("should round the final premium UP to whole G in MHPCO's favor");
100	
101	  // === Quote: integration examples from spec ===
102	  it.todo("should quote newcomer's cursed sword (steel, enchantment 3) at 165 G");
103	  it.todo("should quote 3-year customer's 2nd contract cursed sword (steel, enchantment 7) at 160 G");
104	
105	  // === Claim: basic single damage ===
106	  it.todo("should pay out damage minus 100 G deductible for a single damaged item");
107	  it.todo("should report remainingCap as 2x unmodified insurance sum minus payout after a claim");
108	
109	  // === Claim: enchantment and material clauses ===
110	  it.todo("should pay only 50% reimbursement when damaged item has enchantment >= 8");
111	  it.todo("should pay full reimbursement when damaged item is made of dragon material (overrides 50% clause)");
112	  it.todo("should NOT apply enchantment/material clauses to runes or moonstones");
113	
114	  // === Claim: cap enforcement ===
115	  it.todo("should cap total payout at 2x unmodified insurance sum across multiple claim events");
116	  it.todo("should round payout DOWN to whole G in MHPCO's favor");
117	
118	  // === CLI integration / error cases ===
119	  it.todo("should exit non-zero and write to stderr when quote contains an unknown item type");
120	  it.todo("should exit non-zero when a claim references an item not in the policy");
121	  it.todo("should exit non-zero when a claim has more damage entries of a type than the policy covers");
122	  it.todo("should exit non-zero when a claim contains a negative damage amount");
123	});
