1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	function quoteItem(item: { type: string }): number {
16	  const basePremium = BASE_PREMIUM_BY_ITEM_TYPE[item.type];
17	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
18	  return basePremium + firstInsurance;
19	}
20	
21	export function runScenario(scenario: any): unknown {
22	  const items: { type: string }[] = scenario.items ?? [];
23	  const itemsTotal = items.reduce((sum, item) => sum + quoteItem(item), 0);
24	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
25	}
